import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { Input, SearchInput, addToast, localInputToISOWithOffset } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import { createFixedAssetSearchConfig } from '../../../components/search';
import { DocumentFormHeader } from '../../../components/layout';
import df from '../../../styles/documentForm.module.css';

const TEST_ID = 'tscd-dieu-chinh';

const TscdDieuChinhPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const assetSearchConfig = useMemo(() => createFixedAssetSearchConfig(), []);
  const [fixedAssetId, setFixedAssetId] = useState('');
  const [assetCode, setAssetCode] = useState('');
  const [adjustmentDate, setAdjustmentDate] = useState(new Date().toISOString().slice(0, 10));
  const [adjustmentAmount, setAdjustmentAmount] = useState(0);
  const [reason, setReason] = useState('');
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    if (!fixedAssetId) {
      dispatch(addToast({ message: 'TSCĐ là bắt buộc', type: 'error' }));
      return;
    }
    setSaving(true);
    try {
      await tscdService.createAdjustment({
        fixedAssetId,
        adjustmentDate: localInputToISOWithOffset(adjustmentDate),
        adjustmentAmount: Number(adjustmentAmount),
        reason: reason || undefined,
      });
      dispatch(addToast({ message: 'Điều chỉnh TSCĐ thành công', type: 'success' }));
      navigate('/tscd/danh-sach');
    } catch (e: unknown) {
      dispatch(addToast({ message: e instanceof Error ? e.message : 'Lỗi điều chỉnh TSCĐ', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={df.page} data-testid={`${TEST_ID}-form`}>
      <DocumentFormHeader
        onBack={() => navigate('/tscd/danh-sach')}
        title="Điều chỉnh tài sản"
        isNew
        saving={saving}
        saveLabel="Ghi nhận"
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin điều chỉnh</h2>
        <div className={df.row4}>
          <div className={df.spanCol2} data-testid={`${TEST_ID}-field-fixedAssetId`}>
            <label className={df.label}>TSCĐ *</label>
            <SearchInput
              config={assetSearchConfig}
              value={fixedAssetId}
              primaryDisplay={assetCode}
              onChange={a => { setFixedAssetId(a.id); setAssetCode(a.code); }}
              onClear={() => { setFixedAssetId(''); setAssetCode(''); }}
              showLabel={false}
              showSecondaryInput={false}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Ngày điều chỉnh</label>
            <Input type="date" value={adjustmentDate} onChange={e => setAdjustmentDate(e.target.value)} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Giá trị điều chỉnh (+/-)</label>
            <Input type="number" value={String(adjustmentAmount)} onChange={e => setAdjustmentAmount(Number(e.target.value))} />
          </div>
        </div>
        <div className={df.row4}>
          <div className={`${df.field} ${df.spanCol3}`}>
            <label className={df.label}>Lý do</label>
            <textarea className={df.textarea} value={reason} onChange={e => setReason(e.target.value)} rows={1} />
          </div>
          <div className={df.field} aria-hidden />
        </div>
      </div>
    </div>
  );
};

export default TscdDieuChinhPage;
